import { readFileSync, writeFileSync } from 'fs';
import XLSX from 'xlsx';
import { computeModel, BASE_CASE } from '../engine.js';
import { readCell } from '../lib/excel-parser.mjs';

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------

const EXCEL_PATH = '{{EXCEL_PATH}}';
const TOLERANCE = 0.01; // 1% acceptable deviation

// Map of output keys to Excel cell locations
const OUTPUT_CELLS = {
  // 'returns.grossMOIC':  { sheet: 'Summary', cell: 'C15' },
  // 'returns.netMOIC':    { sheet: 'Summary', cell: 'C16' },
  // 'returns.grossIRR':   { sheet: 'Summary', cell: 'C17' },
  // 'returns.netIRR':     { sheet: 'Summary', cell: 'C18' },
  // 'waterfall.lpTotal':  { sheet: 'Waterfall', cell: 'D30' },
  // 'waterfall.gpCarry':  { sheet: 'Waterfall', cell: 'E30' },
  // {{OUTPUT_CELLS}}
};

// Monotonicity invariants: [inputKey, direction, outputKey, outputDirection]
// 'up' means increasing input, 'down' means expected output should decrease
const MONOTONICITY_TESTS = [
  // ['acquisitionPrice', 'up', 'returns.grossMOIC', 'down'],
  // ['exitCapRate', 'up', 'exitValuation.grossExitValue', 'down'],
  // ['holdPeriodYears', 'up', 'returns.grossIRR', 'down'],
  // {{MONOTONICITY_TESTS}}
];

// ---------------------------------------------------------------------------
// Utilities
// ---------------------------------------------------------------------------

function getNestedValue(obj, path) {
  return path.split('.').reduce((curr, key) => curr?.[key], obj);
}

function formatValue(v) {
  if (v == null) return 'null';
  if (Math.abs(v) >= 1000) return '$' + Math.round(v).toLocaleString('en-US');
  if (Math.abs(v) < 1 && v !== 0) return (v * 100).toFixed(4) + '%';
  return v.toFixed(4);
}

function log(icon, msg) {
  console.log(`  ${icon}  ${msg}`);
}

// ---------------------------------------------------------------------------
// Test 1: Base Case Accuracy
// ---------------------------------------------------------------------------

function testBaseCase(wb) {
  console.log('\n--- Base Case Accuracy ---\n');
  const result = computeModel(BASE_CASE);
  const tests = [];

  for (const [key, loc] of Object.entries(OUTPUT_CELLS)) {
    const cell = readCell(wb, loc.sheet, loc.cell);
    const expected = cell.value;
    const actual = getNestedValue(result, key);

    if (expected == null || actual == null) {
      log('\u26A0\uFE0F', `${key}: expected=${expected}, actual=${actual} (SKIP)`);
      tests.push({ key, expected, actual, deviation: null, passed: false });
      continue;
    }

    const deviation = expected !== 0
      ? Math.abs((actual - expected) / expected)
      : Math.abs(actual - expected);

    const passed = deviation <= TOLERANCE;
    const icon = passed ? '\u2705' : '\u274C';
    log(icon, `${key}: expected=${formatValue(expected)}, got=${formatValue(actual)}, dev=${(deviation * 100).toFixed(4)}%`);

    tests.push({
      key,
      expected,
      actual,
      deviation,
      deviationPercent: (deviation * 100).toFixed(4) + '%',
      passed,
    });
  }

  return tests;
}

// ---------------------------------------------------------------------------
// Test 2: Input Cascade
// ---------------------------------------------------------------------------

function testInputCascade() {
  console.log('\n--- Input Cascade (no-crash check) ---\n');
  const steps = 5;
  let errors = 0;

  for (const [key, baseValue] of Object.entries(BASE_CASE)) {
    if (typeof baseValue !== 'number') continue;

    const min = baseValue * 0.5;
    const max = baseValue * 2.0;
    const step = (max - min) / (steps - 1);

    for (let i = 0; i < steps; i++) {
      const testValue = min + step * i;
      try {
        const testInputs = { ...BASE_CASE, [key]: testValue };
        const result = computeModel(testInputs);
        // Basic sanity: result should be an object
        if (!result || typeof result !== 'object') throw new Error('Result is not an object');
      } catch (err) {
        log('\u274C', `${key}=${testValue.toFixed(2)}: ${err.message}`);
        errors++;
      }
    }
  }

  if (errors === 0) {
    log('\u2705', `All inputs cascaded across range without errors`);
  } else {
    log('\u274C', `${errors} cascade errors found`);
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Test 3: Monotonicity Invariants
// ---------------------------------------------------------------------------

function testMonotonicity() {
  console.log('\n--- Monotonicity Invariants ---\n');
  const results = [];

  for (const [inputKey, inputDir, outputKey, outputDir] of MONOTONICITY_TESTS) {
    const baseValue = BASE_CASE[inputKey];
    if (baseValue == null || typeof baseValue !== 'number') continue;

    const lowInputs = { ...BASE_CASE, [inputKey]: baseValue * 0.8 };
    const highInputs = { ...BASE_CASE, [inputKey]: baseValue * 1.2 };

    const lowResult = computeModel(lowInputs);
    const highResult = computeModel(highInputs);

    const lowOutput = getNestedValue(lowResult, outputKey);
    const highOutput = getNestedValue(highResult, outputKey);

    if (lowOutput == null || highOutput == null) {
      const desc = `${inputKey} \u2191 \u2192 ${outputKey} ${outputDir === 'down' ? '\u2193' : '\u2191'}`;
      log('\u26A0\uFE0F', `${desc}: null output (SKIP)`);
      results.push({ description: desc, passed: false });
      continue;
    }

    let passed;
    if (outputDir === 'down') {
      passed = highOutput <= lowOutput;
    } else {
      passed = highOutput >= lowOutput;
    }

    const desc = `${inputKey} \u2191 \u2192 ${outputKey} ${outputDir === 'down' ? '\u2193' : '\u2191'} (${formatValue(lowOutput)} \u2192 ${formatValue(highOutput)})`;
    log(passed ? '\u2705' : '\u274C', desc);

    results.push({ description: desc, passed });
  }

  return results;
}

// ---------------------------------------------------------------------------
// Test 4: Internal Consistency
// ---------------------------------------------------------------------------

function testConsistency() {
  console.log('\n--- Internal Consistency ---\n');
  const result = computeModel(BASE_CASE);
  const checks = [];

  // Check: LP + GP = Total distributed
  if (result.waterfall) {
    const lpGpSum = (result.waterfall.lpTotal || 0) + (result.waterfall.gpCarry || 0);
    const total = result.waterfall.totalDistributed || lpGpSum;
    const diff = Math.abs(lpGpSum - total);
    const passed = diff < 1; // $1 tolerance
    log(passed ? '\u2705' : '\u274C', `LP + GP = Total: ${formatValue(lpGpSum)} vs ${formatValue(total)}`);
    checks.push({ description: 'LP + GP = Total distributed', passed, detail: `diff=${formatValue(diff)}` });
  }

  // Check: Gross MOIC > Net MOIC
  if (result.returns?.grossMOIC != null && result.returns?.netMOIC != null) {
    const passed = result.returns.grossMOIC >= result.returns.netMOIC;
    log(passed ? '\u2705' : '\u274C', `Gross MOIC (${result.returns.grossMOIC.toFixed(2)}x) >= Net MOIC (${result.returns.netMOIC.toFixed(2)}x)`);
    checks.push({ description: 'Gross MOIC >= Net MOIC', passed });
  }

  // Check: Gross IRR > Net IRR
  if (result.returns?.grossIRR != null && result.returns?.netIRR != null) {
    const passed = result.returns.grossIRR >= result.returns.netIRR;
    log(passed ? '\u2705' : '\u274C', `Gross IRR (${(result.returns.grossIRR * 100).toFixed(2)}%) >= Net IRR (${(result.returns.netIRR * 100).toFixed(2)}%)`);
    checks.push({ description: 'Gross IRR >= Net IRR', passed });
  }

  // Check: MOIC > 1 implies IRR > 0
  if (result.returns?.grossMOIC != null && result.returns?.grossIRR != null) {
    const moicAboveOne = result.returns.grossMOIC > 1.0;
    const irrPositive = result.returns.grossIRR > 0;
    const passed = moicAboveOne === irrPositive;
    log(passed ? '\u2705' : '\u274C', `MOIC > 1 (${moicAboveOne}) matches IRR > 0 (${irrPositive})`);
    checks.push({ description: 'MOIC > 1 iff IRR > 0', passed });
  }

  return checks;
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

async function runEval() {
  console.log('='.repeat(60));
  console.log('  excel-to-engine — Evaluation Suite');
  console.log('='.repeat(60));

  let wb;
  try {
    wb = XLSX.readFile(EXCEL_PATH);
  } catch (err) {
    console.error(`\nCannot read Excel file: ${EXCEL_PATH}`);
    console.error(err.message);
    console.error('\nSkipping base case accuracy test. Other tests will still run.\n');
    wb = null;
  }

  const baseCaseResults = wb ? testBaseCase(wb) : [];
  const cascadeErrors = testInputCascade();
  const monotonicityResults = testMonotonicity();
  const consistencyResults = testConsistency();

  // Summary
  const basePassed = baseCaseResults.filter(r => r.passed).length;
  const baseTotal = baseCaseResults.length;
  const monoPassed = monotonicityResults.filter(r => r.passed).length;
  const monoTotal = monotonicityResults.length;
  const consPassed = consistencyResults.filter(r => r.passed).length;
  const consTotal = consistencyResults.length;

  const allPassed = basePassed === baseTotal && cascadeErrors === 0 &&
                    monoPassed === monoTotal && consPassed === consTotal;

  console.log('\n' + '='.repeat(60));
  console.log(allPassed ? '  ALL TESTS PASSED' : '  SOME TESTS FAILED');
  console.log('='.repeat(60));
  console.log(`  Base Case:    ${basePassed}/${baseTotal}`);
  console.log(`  Cascade:      ${cascadeErrors === 0 ? 'PASS' : cascadeErrors + ' errors'}`);
  console.log(`  Monotonicity: ${monoPassed}/${monoTotal}`);
  console.log(`  Consistency:  ${consPassed}/${consTotal}`);
  console.log('='.repeat(60));

  // Write results for dashboard
  const evalResults = {
    timestamp: new Date().toISOString(),
    tolerance: TOLERANCE,
    allPassed,
    baseCaseResults,
    monotonicityResults,
    consistencyResults,
    cascadeErrors,
  };

  try {
    writeFileSync(
      new URL('./eval-results.json', import.meta.url),
      JSON.stringify(evalResults, null, 2)
    );
    console.log('\nResults written to tests/eval-results.json');
  } catch (err) {
    console.warn('\nCould not write eval-results.json:', err.message);
  }

  process.exit(allPassed ? 0 : 1);
}

runEval();
